/* ── SPECTROGRAM COLOR PALETTE ────────────────────────────────
   Maps a normalised intensity value (0 = min, 1 = max) to an
   RGB color matching the palette used in the PNG spectrograms.

   The palette runs: black → deep purple → magenta → red →
                     orange → amber → yellow → pale yellow

   TWEAK: Change the hex stop colors to restyle the palette.
   TWEAK: Adjust the numeric thresholds to shift where each
          color band appears along the intensity scale.
   TWEAK: Add or remove stops for a finer/coarser gradient.    */
function spectroColor(v) {
  /* v = 0…1 (normalised intensity) */
  const stops = [
    [0.00, [0,   0,   0  ]],   /* silence  → black        */
    [0.12, [10,  0,   40 ]],   /* very low → deep indigo  */
    [0.25, [60,  0,   90 ]],   /* low      → dark purple  */
    [0.38, [140, 0,   100]],   /* low-mid  → magenta      */
    [0.50, [192, 0,   60 ]],   /* mid      → crimson      */
    [0.62, [232, 72,  0  ]],   /* mid-high → orange-red   */
    [0.74, [255, 140, 0  ]],   /* high     → amber        */
    [0.86, [255, 208, 0  ]],   /* very high→ yellow       */
    [1.00, [255, 255, 192]],   /* peak     → pale yellow  */
  ];
  for (let i = 1; i < stops.length; i++) {
    const [t0, c0] = stops[i - 1];
    const [t1, c1] = stops[i];
    if (v <= t1) {
      const ratio = (v - t0) / (t1 - t0);
      const r = Math.round(c0[0] + (c1[0] - c0[0]) * ratio);
      const g = Math.round(c0[1] + (c1[1] - c0[1]) * ratio);
      const b = Math.round(c0[2] + (c1[2] - c0[2]) * ratio);
      return [r, g, b];
    }
  }
  return stops[stops.length - 1][1];
}


/* ── CANVAS SETUP ─────────────────────────────────────────────
   The spectrogram canvas fills the full width of its wrapper
   and resizes automatically when the window changes size.     */
const canvas = document.getElementById('timeline-canvas');
const ctx    = canvas.getContext('2d');
let canvasW  = 0;
let canvasH  = 0;

function resizeCanvas() {
  canvasW = canvas.parentElement.clientWidth;

  /* TWEAK: Canvas height in pixels — keep in sync with
     #timeline-canvas { height } in style.css            */
  canvasH = 160;

  canvas.width  = canvasW;
  canvas.height = canvasH;
  redrawSpectrogram();
}
window.addEventListener('resize', resizeCanvas);


/* ── SPECTROGRAM STATE ─────────────────────────────────────────
   revealedCols tracks how many time columns have been "revealed"
   (painted) so far during playback. Columns to the right of the
   playhead remain dark until the audio reaches them.           */
let currentKey      = null;
let currentDuration = 0;
let revealedCols    = 0;   /* how many time-columns are shown   */

/* Pre-built ImageData caches: one full-resolution image per
   track, built once when first selected to avoid per-frame
   pixel math.                                                   */
const imgCache = {};


/* ── BUILD FULL SPECTROGRAM IMAGE ─────────────────────────────
   Converts the flat Uint8 data array for one track into a full
   ImageData object at canvas resolution. Called once per track
   on first selection and cached.                               */
function buildImage(key) {
  if (imgCache[key]) return imgCache[key];

  const { freqBins, timeCols, data } = SPEC[key];
  const imgData = ctx.createImageData(canvasW, canvasH);
  const px = imgData.data; /* Uint8ClampedArray, RGBA */

  for (let cy = 0; cy < canvasH; cy++) {
    /* Map canvas row → frequency bin (row 0 = top = high freq) */
    const fi = Math.floor((cy / canvasH) * freqBins);

    for (let cx = 0; cx < canvasW; cx++) {
      /* Map canvas column → time column */
      const ti = Math.floor((cx / canvasW) * timeCols);

      const val   = data[fi * timeCols + ti] / 255; /* 0–1 */
      const [r, g, b] = spectroColor(val);
      const idx   = (cy * canvasW + cx) * 4;
      px[idx]     = r;
      px[idx + 1] = g;
      px[idx + 2] = b;
      px[idx + 3] = 255;
    }
  }

  imgCache[key] = imgData;
  return imgData;
}


/* ── DRAW SPECTROGRAM ─────────────────────────────────────────
   Paints the canvas:
     1. Dark background for the unrevealed (future) portion
     2. Full spectrogram image, clipped to the revealed width
     3. Thin playhead line at the reveal boundary             */
function redrawSpectrogram() {
  /* TWEAK: Background color for the unrevealed area           */
  ctx.fillStyle = '#0a0a0a';
  ctx.fillRect(0, 0, canvasW, canvasH);

  if (!currentKey) return;

  const imgData   = buildImage(currentKey);
  const { timeCols } = SPEC[currentKey];

  /* How many canvas pixels correspond to revealedCols */
  const revealPx = Math.floor((revealedCols / timeCols) * canvasW);

  if (revealPx > 0) {
    /* Draw the pre-built image into an offscreen canvas so we
       can clip it to revealPx width without re-computing pixels */
    if (!redrawSpectrogram._off || redrawSpectrogram._offKey !== currentKey) {
      redrawSpectrogram._off = document.createElement('canvas');
      redrawSpectrogram._off.width  = canvasW;
      redrawSpectrogram._off.height = canvasH;
      redrawSpectrogram._off.getContext('2d').putImageData(imgData, 0, 0);
      redrawSpectrogram._offKey = currentKey;
    }
    ctx.drawImage(redrawSpectrogram._off, 0, 0, revealPx, canvasH, 0, 0, revealPx, canvasH);
  }

  /* Playhead line */
  if (revealPx > 0 && revealPx < canvasW) {
    /* TWEAK: Playhead color and opacity */
    ctx.strokeStyle = 'rgba(255, 255, 255, 0.7)';

    /* TWEAK: Playhead line thickness in pixels */
    ctx.lineWidth = 1.5;

    ctx.beginPath();
    ctx.moveTo(revealPx, 0);
    ctx.lineTo(revealPx, canvasH);
    ctx.stroke();
  }
}


/* ── WEB AUDIO STATE ──────────────────────────────────────────  */
let audioCtx     = null;
let currentAudio = null;
let animId       = null;
let currentBtn   = null;


/* ── SELECT SOUND (button click handler) ──────────────────────
   Wired to onclick="selectSound(this)" on each button.        */
function selectSound(btn) {
  const key = btn.dataset.audio;
  if (currentBtn === btn && currentAudio && !currentAudio.paused) {
    stopAll();
    return;
  }
  stopAll();
  currentBtn      = btn;
  btn.classList.add('active');
  currentKey      = key;
  currentDuration = AUDIO[key].duration;
  revealedCols    = 0;

  /* Invalidate offscreen cache so the correct track renders */
  redrawSpectrogram._off    = null;
  redrawSpectrogram._offKey = null;
  redrawSpectrogram();

  playAudio(key);
}


/* ── STOP ALL PLAYBACK ────────────────────────────────────────  */
function stopAll() {
  if (currentAudio) { currentAudio.pause(); currentAudio.currentTime = 0; }
  if (animId) cancelAnimationFrame(animId);
  if (currentBtn) currentBtn.classList.remove('active');
  currentBtn  = null;
  currentKey  = null;
  revealedCols = 0;
  redrawSpectrogram._off = null;
}


/* ── PLAY AUDIO ───────────────────────────────────────────────  */
function playAudio(key) {
  if (!audioCtx) {
    audioCtx = new (window.AudioContext || window.webkitAudioContext)();
  }
  const audio = new Audio(AUDIO[key].src);
  currentAudio = audio;

  const src = audioCtx.createMediaElementSource(audio);
  src.connect(audioCtx.destination); /* no analyser needed — spectrogram is pre-computed */

  audio.play();
  audio.onended = () => {
    if (currentBtn) currentBtn.classList.remove('active');
    currentBtn   = null;
    currentKey   = null;
    revealedCols = 0;
    cancelAnimationFrame(animId);
    redrawSpectrogram();
  };
  animate();
}


/* ── ANIMATION LOOP ───────────────────────────────────────────
   Each frame, maps the current playback position to a column
   count and triggers a canvas repaint.                        */
function animate() {
  animId = requestAnimationFrame(animate);
  if (!currentAudio || !currentKey) return;

  const { timeCols } = SPEC[currentKey];
  const elapsed = currentAudio.currentTime;                   /* seconds */
  revealedCols  = Math.floor((elapsed / currentDuration) * timeCols);
  redrawSpectrogram();
}


/* ── INIT ─────────────────────────────────────────────────────  */
resizeCanvas();
